from flask import Flask, request, jsonify
from collections import defaultdict, Counter
from sklearn.model_selection import train_test_split
from sklearn.ensemble import RandomForestClassifier
from sklearn.datasets import load_digits
import numpy as np

app = Flask(__name__)

# In-memory storage for image labels
image_labels = defaultdict(list)

# Endpoint to submit labels
@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    image_labels[image_id].append(label)
    return jsonify({"message": "Label submitted successfully"}), 200

# Function to aggregate labels using majority voting
def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in image_labels.items():
        if labels:
            most_common_label = Counter(labels).most_common(1)[0][0]
            aggregated_labels[image_id] = most_common_label
    return aggregated_labels

# Endpoint to train model
@app.route('/train_model', methods=['POST'])
def train_model():
    aggregated_labels = aggregate_labels()
    # Load example dataset (replace with actual image data and labels)
    digits = load_digits()
    X = digits.data
    y = np.array([aggregated_labels.get(i, -1) for i in range(len(X))])
    
    # Filter out images without consensus
    valid_indices = y != -1
    X = X[valid_indices]
    y = y[valid_indices]

    # Train model without validation
    model = RandomForestClassifier()
    model.fit(X, y)
    
    return jsonify({"message": "Model trained successfully"}), 200

if __name__ == '__main__':
    app.run(debug=True)